import itertools

def solve_24_game():
    solutions = set()
    numbers = range(1, 14)
    for a, b, c, d in itertools.combinations_with_replacement(numbers, 4):
        for permutation in set(itertools.permutations([a, b, c, d])):
            for ops in itertools.product(['+', '-', '*', '/'], repeat=3):
                # Case 1: ((a op1 b) op2 c) op3 d
                try:
                    val1 = compute(compute(compute(permutation[0], permutation[1], ops[0]), permutation[2], ops[1]), permutation[3], ops[2])
                    if abs(val1 - 24) < 1e-6:
                        solutions.add(tuple(sorted((a, b, c, d))))
                except ZeroDivisionError:
                    pass
                # Case 2: (a op1 (b op2 c)) op3 d
                try:
                    val2 = compute(compute(permutation[0], compute(permutation[1], permutation[2], ops[1]), ops[0]), permutation[3], ops[2])
                    if abs(val2 - 24) < 1e-6:
                        solutions.add(tuple(sorted((a, b, c, d))))
                except ZeroDivisionError:
                    pass
                # Case 3: a op1 (b op2 (c op3 d))
                try:
                    val3 = compute(permutation[0], compute(permutation[1], compute(permutation[2], permutation[3], ops[2]), ops[1]), ops[0])
                    if abs(val3 - 24) < 1e-6:
                        solutions.add(tuple(sorted((a, b, c, d))))
                except ZeroDivisionError:
                    pass
                # Case 4: (a op1 b) op2 (c op3 d)
                try:
                    val4 = compute(compute(permutation[0], permutation[1], ops[0]), compute(permutation[2], permutation[3], ops[2]), ops[1])
                    if abs(val4 - 24) < 1e-6:
                        solutions.add(tuple(sorted((a, b, c, d))))
                except ZeroDivisionError:
                    pass
                # Case 5: a op1 ((b op2 c) op3 d)
                try:
                    val5 = compute(permutation[0], compute(compute(permutation[1], permutation[2], ops[1]), permutation[3], ops[2]), ops[0])
                    if abs(val5 - 24) < 1e-6:
                        solutions.add(tuple(sorted((a, b, c, d))))
                except ZeroDivisionError:
                    pass
    # Sort the solutions and print
    for sol in sorted(solutions):
        print(sol)

def compute(a, b, op):
    if op == '+':
        return a + b
    elif op == '-':
        return a - b
    elif op == '*':
        return a * b
    elif op == '/':
        return a / b

