def find_proper_divisors(n):
    """返回n的所有真因子(不包括n本身)"""
    if n == 1:
        return []
    divisors = {1}
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            divisors.add(i)
            divisors.add(n // i)
    return sorted(divisors)

def is_abundant(n):
    """判断一个数是否是丰数"""
    divisors = find_proper_divisors(n)
    return sum(divisors) > n

