def sum_proper_divisors(n):
    if n == 1:
        return 0
    sum_div = 1  # 1 is a proper divisor for any n > 1
    sqrt_n = int(n ** 0.5)
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            sum_div += i
            counterpart = n // i
            if counterpart != i:
                sum_div += counterpart
    return sum_div

def find_abundant_numbers(limit):
    abundant_numbers = []
    for n in range(1, limit + 1):
        if sum_proper_divisors(n) > n:
            abundant_numbers.append(n)
    return abundant_numbers

