def execute_brainfuck(program):
    array = {}
    ptr = 0
    array[ptr] = 0
    pc = 0
    loop_stack = []

    # Preprocess loop pairs for faster jumping
    loop_pairs = {}
    stack = []
    for i, cmd in enumerate(program):
        if cmd == '[':
            stack.append(i)
        elif cmd == ']':
            if stack:
                start = stack.pop()
                loop_pairs[start] = i
                loop_pairs[i] = start

    while pc < len(program):
        cmd = program[pc]

        if cmd == '>':
            ptr += 1
            if ptr not in array:
                array[ptr] = 0
        elif cmd == '<':
            ptr -= 1
            if ptr not in array:
                array[ptr] = 0
        elif cmd == '+':
            array[ptr] = (array[ptr] + 1) % 256
        elif cmd == '-':
            array[ptr] = (array[ptr] - 1) % 256
        elif cmd == '.':
            print(chr(array[ptr]), end='')
        elif cmd == '[':
            if array[ptr] == 0:
                pc = loop_pairs[pc]
        elif cmd == ']':
            if array[ptr] != 0:
                pc = loop_pairs[pc]

        pc += 1

