def is_valid_luhn(card_number):
    # Remove all spaces and join the digits
    digits = card_number.replace(" ", "")
    if len(digits) != 16 or not digits.isdigit():
        return False

    total = 0
    for i in range(16):
        digit = int(digits[i])
        if i % 2 == 1:  # Even positions (0-based index)
            total += digit
        else:  # Odd positions (0-based index)
            doubled = digit * 2
            total += doubled // 10 + doubled % 10

    return total % 10 == 0

def validate_card_numbers(card_numbers):
    valid_cards = []
    for card in card_numbers:
        if is_valid_luhn(card):
            valid_cards.append(card)
    return valid_cards

