def binomial_coefficient(n, k):
    if k < 0 or k > n:
        return 0
    result = 1
    if k > n - k:
        k = n - k
    for i in range(1, k + 1):
        result = result * (n - k + i) // i
    return result

def catalan_number(n):
    return binomial_coefficient(2 * n, n) // (n + 1)

