def collatz_stopping_time(n):
    """Calculate the stopping time for a given number n in the Collatz sequence."""
    steps = 0
    while n != 1:
        if n % 2 == 0:
            n = n // 2
        else:
            n = 3 * n + 1
        steps += 1
    return steps

