import math

def farey_sequence(n):
    fractions = []
    for d in range(1, n + 1):
        for h in range(0, d + 1):
            if math.gcd(h, d) == 1:
                fractions.append((h, d))
    # 按分数值排序
    fractions.sort(key=lambda x: x[0] / x[1])
    return fractions

