def fen_to_unicode(fen):
    # Mapping of FEN piece codes to Unicode chess symbols
    piece_symbols = {
        'p': '♟', 'n': '♞', 'b': '♝', 'r': '♜', 'q': '♛', 'k': '♚',
        'P': '♙', 'N': '♘', 'B': '♗', 'R': '♖', 'Q': '♕', 'K': '♔'
    }

    # Split the FEN string to get the board part
    board_part = fen.split()[0]

    # Process each rank in the FEN string
    board = []
    for rank in board_part.split('/'):
        rank_str = ''
        for char in rank:
            if char.isdigit():
                # Add the specified number of spaces
                rank_str += ' ' * int(char)
            else:
                # Add the corresponding Unicode piece
                rank_str += piece_symbols[char]
        board.append(rank_str)

    # Return the board as a string with newlines
    return '\n'.join(board)

