def gijswijt_sequence(n_terms):
    sequence = [1]
    for i in range(1, n_terms):
        max_k = 1
        # Check possible block lengths from largest to smallest
        for l in range(len(sequence), 0, -1):
            # Number of complete blocks of length l that fit
            max_possible = len(sequence) // l
            if max_possible < max_k:
                continue  # Can't improve current max_k
            # Check all possible numbers of repetitions
            for k in range(max_possible, max_k - 1, -1):
                # Check if last k blocks of length l are equal
                block = sequence[-l:]
                valid = True
                for m in range(1, k):
                    start = -l * (m + 1)
                    end = -l * m if m != 0 else None
                    if sequence[start:end] != block:
                        valid = False
                        break
                if valid:
                    max_k = k
                    break  # No need to check smaller k for this l
            if max_k == max_possible:
                break  # Can't do better than this for smaller l
        sequence.append(max_k)
    return sequence

