def generate_inventory_sequence(length):
    sequence = [0]
    while len(sequence) < length:
        sequence.append(0)  # Add 0 to trigger inventory
        k = 0
        while True:
            count = sequence.count(k)
            sequence.append(count)
            if k + 1 not in sequence:
                break
            k += 1
            if len(sequence) >= length:
                break
        if len(sequence) >= length:
            break
    return sequence[:length]

