def find_leyland_numbers(max_limit):
    leyland_numbers = set()

    x = 2
    while True:
        y = 2
        while y <= x:
            number = x ** y + y ** x
            if number > max_limit:
                break
            leyland_numbers.add(number)
            y += 1
        if y == 2:  # means even x^2 + 2^x > max_limit
            break
        x += 1

    return sorted(leyland_numbers)

