def count_lucky_tickets(d, b):
    half = d // 2
    max_sum = (b - 1) * half

    # Initialize a DP table where dp[i][j] represents the number of i-digit numbers with sum j
    dp = [[0] * (max_sum + 1) for _ in range(half + 1)]
    dp[0][0] = 1

    for i in range(1, half + 1):
        for j in range(max_sum + 1):
            for k in range(b):
                if j >= k:
                    dp[i][j] += dp[i - 1][j - k]

    total = 0
    for s in range(max_sum + 1):
        total += dp[half][s] * dp[half][s]

    return total

