def is_complete_mahjong_hand(hand):
    # Define tile categories
    characters = ['🀇', '🀈', '🀉', '🀊', '🀋', '🀌', '🀍', '🀎', '🀏']
    bamboo = ['🀐', '🀑', '🀒', '🀓', '🀔', '🀕', '🀖', '🀗', '🀘']
    circles = ['🀙', '🀚', '🀛', '🀜', '🀝', '🀞', '🀟', '🀠', '🀡']
    honors = ['🀀', '🀁', '🀂', '🀃', '🀄', '🀅', '🀆']

    # Count tile frequencies
    tile_counts = {}
    for tile in hand:
        tile_counts[tile] = tile_counts.get(tile, 0) + 1

    # Check for Seven Pairs
    def is_seven_pairs(counts):
        pairs = [t for t, cnt in counts.items() if cnt == 2]
        return len(pairs) == 7

    # Check for Thirteen Orphans
    def is_thirteen_orphans(counts):
        required_tiles = set([characters[0], characters[-1], 
                             bamboo[0], bamboo[-1], 
                             circles[0], circles[-1]] + honors)
        # Check all required tiles present
        if not required_tiles.issubset(counts.keys()):
            return False
        # Check only one duplicate
        duplicates = [t for t, cnt in counts.items() if cnt == 2]
        return len(duplicates) == 1 and duplicates[0] in required_tiles

    # Check for standard 4 melds + 1 pair
    def is_standard_win(counts):
        # Make a copy to modify
        counts = counts.copy()
        # Find a pair
        pairs = [t for t, cnt in counts.items() if cnt >= 2]
        for pair_tile in pairs:
            temp_counts = counts.copy()
            temp_counts[pair_tile] -= 2
            if temp_counts[pair_tile] == 0:
                del temp_counts[pair_tile]

            melds_found = 0
            # Try to find 4 melds
            while melds_found < 4:
                found_meld = False
                # Check for triplets first
                for tile in list(temp_counts.keys()):
                    if temp_counts[tile] >= 3:
                        temp_counts[tile] -= 3
                        if temp_counts[tile] == 0:
                            del temp_counts[tile]
                        melds_found += 1
                        found_meld = True
                        break

                if found_meld:
                    continue

                # Check for sequences in number tiles
                for suit in [characters, bamboo, circles]:
                    for i in range(7):  # Max start index for sequence
                        tiles = [suit[i], suit[i+1], suit[i+2]]
                        if all(t in temp_counts for t in tiles):
                            if all(temp_counts[t] > 0 for t in tiles):
                                for t in tiles:
                                    temp_counts[t] -= 1
                                    if temp_counts[t] == 0:
                                        del temp_counts[t]
                                melds_found += 1
                                found_meld = True
                                break
                    if found_meld:
                        break

                if not found_meld:
                    break

            if melds_found == 4 and len(temp_counts) == 0:
                return True
        return False

    # Check all winning conditions
    return (is_standard_win(tile_counts) or 
            is_seven_pairs(tile_counts) or 
            is_thirteen_orphans(tile_counts))

