def find_shortest_path(maze):
    # Find start and end positions
    start = end = None
    for i in range(len(maze)):
        row = maze[i]
        if 'S' in row:
            start = (i, row.index('S'))
        if 'E' in row:
            end = (i, row.index('E'))

    if not start or not end:
        return maze  # No start or end found

    # Directions: up, down, left, right
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    rows, cols = len(maze), len(maze[0])

    # BFS setup
    queue = deque([start])
    parent = {start: None}

    while queue:
        current = queue.popleft()
        if current == end:
            break  # Found the end

        for direction in directions:
            ni, nj = current[0] + direction[0], current[1] + direction[1]
            if 0 <= ni < rows and 0 <= nj < cols:
                next_pos = (ni, nj)
                if (maze[ni][nj] == ' ' or maze[ni][nj] == 'E') and next_pos not in parent:
                    parent[next_pos] = current
                    queue.append(next_pos)

    # Reconstruct path if found
    if end not in parent:
        return maze  # No path found

    # Backtrack from end to start
    path = set()
    current = end
    while current != start:
        path.add(current)
        current = parent[current]

    # Create new maze with path marked
    new_maze = []
    for i in range(rows):
        new_row = []
        for j in range(cols):
            if (i, j) in path and maze[i][j] != 'E':
                new_row.append('.')
            else:
                new_row.append(maze[i][j])
        new_maze.append(''.join(new_row))

    return new_maze

