def solve_n_queens(n):
    def is_safe(board, row, col):
        # Check if a queen can be placed at board[row][col]
        for i in range(col):
            if board[i] == row or \
               board[i] - i == row - col or \
               board[i] + i == row + col:
                return False
        return True

    def backtrack(col, board, solutions):
        if col == n:
            solutions.append(board.copy())
            return
        for row in range(n):
            if is_safe(board, row, col):
                board[col] = row
                backtrack(col + 1, board, solutions)

    solutions = []
    board = [-1] * n
    backtrack(0, board, solutions)
    return solutions

