def generate_polyominoes(max_n):
    from collections import defaultdict

    def rotate(poly):
        return {(y, -x) for (x, y) in poly}

    def reflect(poly):
        return {(-x, y) for (x, y) in poly}

    def normalize(poly):
        min_x = min(x for x, y in poly)
        min_y = min(y for x, y in poly)
        return frozenset((x - min_x, y - min_y) for x, y in poly)

    def get_variants(poly):
        variants = set()
        current = poly
        for _ in range(4):
            variants.add(normalize(current))
            variants.add(normalize(reflect(current)))
            current = rotate(current)
        return variants

    polyominoes = defaultdict(list)
    polyominoes[1] = [{(0, 0)}]

    for n in range(2, max_n + 1):
        new_polyominoes = set()
        for poly in polyominoes[n - 1]:
            for (x, y) in poly:
                for (dx, dy) in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                    new_square = (x + dx, y + dy)
                    if new_square not in poly:
                        new_poly = poly.copy()
                        new_poly.add(new_square)
                        normalized = normalize(new_poly)
                        is_new = True
                        for variant in get_variants(new_poly):
                            if variant in new_polyominoes:
                                is_new = False
                                break
                        if is_new:
                            new_polyominoes.add(normalized)
        polyominoes[n] = [set(p) for p in new_polyominoes]

    return polyominoes

