def base62_encode(num):
    if num == 0:
        return '0'
    chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz"
    result = []
    while num > 0:
        num, rem = divmod(num, 62)
        result.append(chars[rem])
    return ''.join(reversed(result))

def solve_grid(grid):
    rows = 9
    cols = 9
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    distance = [[-1 for _ in range(cols)] for _ in range(rows)]
    q = deque()

    # Initialize the queue with all sources
    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == '0':
                q.append((i, j))
                distance[i][j] = 0

    # Perform BFS
    while q:
        x, y = q.popleft()
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < rows and 0 <= ny < cols:
                if grid[nx][ny] == '-' and distance[nx][ny] == -1:
                    distance[nx][ny] = distance[x][y] + 1
                    q.append((nx, ny))

    # Construct the result grid
    result = []
    for i in range(rows):
        row = []
        for j in range(cols):
            if grid[i][j] == '-':
                if distance[i][j] != -1:
                    row.append(base62_encode(distance[i][j]))
                else:
                    row.append('-')
            else:
                row.append(grid[i][j])
        result.append(''.join(row))
    return result

