def si_unit_to_base_components(unit):
    # Define SI prefixes and their factors
    prefixes = {
        'Q': 30, 'R': 27, 'Y': 24, 'Z': 21, 'E': 18, 'P': 15,
        'T': 12, 'G': 9, 'M': 6, 'k': 3, 'h': 2, 'da': 1,
        'd': -1, 'c': -2, 'm': -3, 'μ': -6, 'n': -9, 'p': -12,
        'f': -15, 'a': -18, 'z': -21, 'y': -24, 'r': -27, 'q': -30
    }

    # Define derived units and their base unit equivalents
    derived_units = {
        'rad': {'': 1},
        'sr': {'': 1},
        'Hz': {'s': -1},
        'N': {'kg': 1, 'm': 1, 's': -2},
        'Pa': {'kg': 1, 'm': -1, 's': -2},
        'J': {'kg': 1, 'm': 2, 's': -2},
        'W': {'kg': 1, 'm': 2, 's': -3},
        'C': {'A': 1, 's': 1},
        'V': {'kg': 1, 'm': 2, 's': -3, 'A': -1},
        'F': {'kg': -1, 'm': -2, 's': 4, 'A': 2},
        'Ω': {'kg': 1, 'm': 2, 's': -3, 'A': -2},
        'S': {'kg': -1, 'm': -2, 's': 3, 'A': 2},
        'Wb': {'kg': 1, 'm': 2, 's': -2, 'A': -1},
        'T': {'kg': 1, 's': -2, 'A': -1},
        'H': {'kg': 1, 'm': 2, 's': -2, 'A': -2},
        '°C': {'K': 1},
        'lm': {'cd': 1},
        'lx': {'cd': 1, 'm': -2},
        'Bq': {'s': -1},
        'Gy': {'m': 2, 's': -2},
        'Sv': {'m': 2, 's': -2},
        'kat': {'mol': 1, 's': -1}
    }

    # Special case for gram handling
    if unit.endswith('g') and not unit.endswith('kg'):
        # Handle gram units
        base_unit = 'g'
        prefix_part = unit[:-1]
        if prefix_part == '':  # case of just 'g'
            prefix = ''
        else:
            # Find the longest matching prefix
            possible_prefixes = sorted([p for p in prefixes.keys() if unit.startswith(p)], key=len, reverse=True)
            if possible_prefixes:
                prefix = possible_prefixes[0]
                base_unit = unit[len(prefix):]
            else:
                prefix = ''
                base_unit = unit

        if base_unit == 'g':
            components = {'kg': 1}
            power_of_ten = prefixes.get(prefix, 0) - 3  # convert g to kg (10^-3)
            return power_of_ten, components
    else:
        # Find the longest matching prefix
        prefix = ''
        base_unit = unit
        possible_prefixes = sorted([p for p in prefixes.keys() if unit.startswith(p)], key=len, reverse=True)
        if possible_prefixes:
            prefix = possible_prefixes[0]
            base_unit = unit[len(prefix):]

    power_of_ten = prefixes.get(prefix, 0)

    # Handle base units
    base_units = {'s', 'm', 'kg', 'A', 'K', 'mol', 'cd'}
    if base_unit in base_units:
        components = {base_unit: 1}
    elif base_unit in derived_units:
        components = derived_units[base_unit]
    else:
        raise ValueError(f"Unknown unit: {base_unit}")

    # Special cases for rad and sr
    if base_unit in ['rad', 'sr'] and components == {'': 1}:
        components = {}

    return power_of_ten, components

