        power_of_ten, components = si_unit_to_base_components(unit)

        # Handle power of ten
        if power_of_ten == 0:
            power_part = '1'
        elif power_of_ten == 1:
            power_part = '10'
        else:
            power_part = f'10^{power_of_ten}'

        # Handle components
        component_parts = []
        for base_unit in sorted(components.keys()):
            exponent = components[base_unit]
            if exponent == 1:
                component_parts.append(base_unit)
            else:
                component_parts.append(f'{base_unit}^{exponent}')

        if not component_parts:
            return power_part

        components_str = ' '.join(component_parts)

        if power_part == '1':
            return components_str
        else:
            return f'{power_part} {components_str}'
    except ValueError as e:
        return str(e)

