def sierpinski(n):
    triangles = ["▲"]
    for i in range(1, n + 1):
        max_length = 2 ** i
        new_triangles = []
        for line in triangles:
            new_line = line + ' ' * (max_length - len(line)) + line
            new_triangles.append(line)
            new_triangles.append(new_line)
        triangles = new_triangles
    for line in triangles[:2**n - 1]:
        print(line)

