def is_prime(n):
    """Check if a number is prime."""
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

def prime_factors(n):
    """Return the list of prime factors of n, including multiplicity."""
    if n == 1:
        return []
    factors = []
    # Handle 2 separately
    while n % 2 == 0:
        factors.append(2)
        n = n // 2
    # Check odd divisors up to sqrt(n)
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n = n // i
        i += 2
    if n > 1:
        factors.append(n)
    return factors

def digit_sum(n):
    """Return the sum of the digits of n."""
    return sum(int(d) for d in str(n))

def is_smith(n):
    """Check if a number is a Smith number."""
    if n < 2 or is_prime(n):
        return False
    factors = prime_factors(n)
    # Handle the case where n is 1 or has no prime factors (shouldn't happen for n >= 2)
    if not factors:
        return False
    # Compare digit sum of n and sum of digits of prime factors
    return digit_sum(n) == sum(digit_sum(p) for p in factors)

