def is_valid(board, row, col, num):
    """Check if placing num at (row, col) is valid"""
    # Check row
    if num in board[row]:
        return False

    # Check column
    if num in [board[i][col] for i in range(9)]:
        return False

    # Check 3x3 box
    box_row = (row // 3) * 3
    box_col = (col // 3) * 3
    for i in range(box_row, box_row + 3):
        for j in range(box_col, box_col + 3):
            if board[i][j] == num:
                return False

    return True

def solve_sudoku(board):
    """Solve the Sudoku using backtracking"""
    for row in range(9):
        for col in range(9):
            if board[row][col] == 0:
                for num in range(1, 10):
                    if is_valid(board, row, col, num):
                        board[row][col] = num
                        if solve_sudoku(board):
                            return True
                        board[row][col] = 0
                return False
    return True

def parse_input(args):
    """Parse command line arguments into a Sudoku board"""
    if len(args) != 9:
        raise ValueError("Expected 9 lines of input")

    board = []
    for line in args:
        row = []
        if len(line) != 9:
            raise ValueError("Each line must contain exactly 9 characters")
        for c in line:
            if c == '_':
                row.append(0)
            elif c.isdigit():
                row.append(int(c))
            else:
                raise ValueError(f"Invalid character '{c}' in input")
        board.append(row)
    return board

