def solve_sudoku(board):
    def is_valid(num, pos):
        # Check row
        for i in range(9):
            if board[pos[0]][i] == num and pos[1] != i:
                return False

        # Check column
        for i in range(9):
            if board[i][pos[1]] == num and pos[0] != i:
                return False

        # Check 3x3 box
        box_x = pos[1] // 3
        box_y = pos[0] // 3

        for i in range(box_y*3, box_y*3 + 3):
            for j in range(box_x*3, box_x*3 + 3):
                if board[i][j] == num and (i,j) != pos:
                    return False
        return True

    def find_empty():
        for i in range(9):
            for j in range(9):
                if board[i][j] == 0:
                    return (i, j)  # row, column
        return None

    def solve():
        find = find_empty()
        if not find:
            return True
        else:
            row, col = find

        for num in range(1, 10):
            if is_valid(num, (row, col)):
                board[row][col] = num

                if solve():
                    return True

                board[row][col] = 0

        return False

    solve()
    return board

