def calculate_bowling_score(game):
    rolls = []
    frames = game.split()

    # Process each frame to extract rolls
    for i, frame in enumerate(frames):
        if i < 9:  # First 9 frames
            if 'X' in frame:
                rolls.append(10)
            else:
                for roll in frame:
                    if roll == 'X':
                        continue  # shouldn't happen in first 9 frames except as first roll
                    elif roll == '/':
                        rolls.append(10 - rolls[-1])
                    elif roll == '-':
                        rolls.append(0)
                    elif roll == 'F':
                        rolls.append(0)
                    elif roll in '⑤⑥⑦⑧':
                        # Split counts as whatever pins were actually knocked down
                        # Since we don't know, we'll treat as 1 (minimum for split)
                        rolls.append(1)
                    else:
                        try:
                            rolls.append(int(roll))
                        except:
                            rolls.append(0)  # fallback for unknown characters
        else:  # 10th frame
            for roll in frame:
                if roll == 'X':
                    rolls.append(10)
                elif roll == '/':
                    rolls.append(10 - rolls[-1])
                elif roll == '-':
                    rolls.append(0)
                elif roll == 'F':
                    rolls.append(0)
                elif roll in '⑤⑥⑦⑧':
                    rolls.append(1)
                else:
                    try:
                        rolls.append(int(roll))
                    except:
                        rolls.append(0)

    score = 0
    roll_index = 0

    for frame in range(10):
        if frame < 9:  # First 9 frames
            if rolls[roll_index] == 10:  # Strike
                score += 10
                # Add bonus from next two rolls
                if roll_index + 1 < len(rolls):
                    score += rolls[roll_index + 1]
                if roll_index + 2 < len(rolls):
                    score += rolls[roll_index + 2]
                roll_index += 1
            else:
                if roll_index + 1 < len(rolls):
                    frame_score = rolls[roll_index] + rolls[roll_index + 1]
                    score += frame_score
                    if frame_score == 10:  # Spare
                        if roll_index + 2 < len(rolls):
                            score += rolls[roll_index + 2]
                    roll_index += 2
                else:
                    # Not enough rolls, just add what we have
                    score += rolls[roll_index]
                    roll_index += 1
        else:  # 10th frame
            # Just add all remaining rolls
            while roll_index < len(rolls):
                score += rolls[roll_index]
                roll_index += 1

    return score

