def transpose_sentence(sentence):
    words = sentence.split()
    if not words:
        return ""

    max_length = max(len(word) for word in words)
    transposed = []

    for i in range(max_length):
        column_chars = []
        for word in words:
            if i < len(word):
                column_chars.append(word[i])
        transposed.append("".join(column_chars) + " ")

    return "".join(transposed).strip()

def transpose_sentences(sentences):
    for sentence in sentences:
        print(transpose_sentence(sentence))

