def is_vampire_number(n):
    s = str(n)
    length = len(s)
    if length % 2 != 0:
        return False
    half = length // 2
    fang_pairs = set()
    # Iterate possible fangs
    for i in range(10 ** (half - 1), int(n ** 0.5) + 1):
        if n % i == 0:
            j = n // i
            if j < 10 ** (half - 1) or j >= 10 ** half:
                continue
            # Check digits
            combined = str(i) + str(j)
            if sorted(combined) == sorted(s):
                # Check trailing zeros
                if (i % 10 == 0 and j % 10 == 0):
                    continue
                # Avoid duplicate pairs like (i,j) and (j,i)
                if (j, i) not in fang_pairs:
                    fang_pairs.add((i, j))
    return len(fang_pairs) > 0

def find_vampire_numbers(start, end):
    for n in range(start, end + 1):
        if is_vampire_number(n):
            print(n)

