def zeckendorf_representation(n):
    if n < 1:
        return ""

    # Generate Fibonacci numbers up to n
    fibs = [1, 2]
    while True:
        next_fib = fibs[-1] + fibs[-2]
        if next_fib > n:
            break
        fibs.append(next_fib)

    # Find the Zeckendorf representation
    remaining = n
    result = []
    for num in reversed(fibs):
        if num <= remaining:
            result.append(num)
            remaining -= num
            if remaining == 0:
                break

    # Return the result as a string
    return " + ".join(map(str, result))

